Final Insights and Deliverable


Code
library(gt)

respondent_info &lt;- resp |&gt;
    inner_join(rost |&gt; 
                   filter(tulineno == 1) |&gt; 
                   select(participant_id, age, sex), 
               by = "participant_id")

calc_market_stats &lt;- function(df, label, target_offset = 30) {
    df |&gt;
        group_by(participant_id, survey_weight) |&gt;
        summarize(total_time = sum(time_spent_min), .groups = 'drop') |&gt;
        summarize(
            Demographic = label,
            Low = quantile(total_time, 0.25),
            Typical = median(total_time),
            High = quantile(total_time, 0.75),
            App_Target = Typical + target_offset
        )
}

# Group 1: Stay-at-Home Dads
sahd_stats &lt;- act |&gt;
    filter(level1_code == "030000") |&gt;
    inner_join(respondent_info |&gt;
                   filter(sex == "M", trchildnum &gt; 0, employment_status == "Not in Labor force"), 
               by = "participant_id") |&gt;
    calc_market_stats("Stay-at-Home Dads")

# Group 2: Undergrads 
student_stats &lt;- act |&gt;
    filter(level1_code == "060000") |&gt;
    inner_join(respondent_info |&gt; filter(is_college_student == TRUE), by = "participant_id") |&gt;
    calc_market_stats("College Undergraduates")

# Group 3: Remote Professionals
remote_stats &lt;- act |&gt;
    filter(level1_code == "050000", location == "Home") |&gt;
    inner_join(respondent_info |&gt; filter(employment_status == "Employed"), by = "participant_id") |&gt;
    calc_market_stats("Remote Professionals")

# Final Table
bind_rows(sahd_stats, student_stats, remote_stats) |&gt;
    gt() |&gt;
    tab_header(title = "Market Research: Daily Time Use Targets 📟",
               subtitle = "Figures in minutes per day") |&gt;
    fmt_number(columns = 2:5, decimals = 0) |&gt;
  tab_source_note(md(
      "This table shows how much time three different groups of people—dads at home, college students, and remote workers—spend on their main daily tasks. We looked at the 'typical' amount of time they spend and then added 30 minutes to create an 'App Target.' This target is a goal for how much time we want people to spend using an app or doing an activity. It shows that you can't have the same goal for everyone, because a student's daily schedule looks totally different from a stay-at-home dad's schedule. "))








