4.4: Average Sleep


Code
sleep_per_person &lt;- act |&gt;
    filter(level2_code == "010100") |&gt;
    group_by(participant_id) |&gt;
    summarize(total_sleep_min = sum(time_spent_min, na.rm = TRUE))


sleep_stats &lt;- resp |&gt;
    left_join(sleep_per_person, by = "participant_id") |&gt;
    mutate(total_sleep_min = replace_na(total_sleep_min, 0)) |&gt;
    summarize(
        avg_sleep_hours = weighted.mean(total_sleep_min, w = survey_weight) / 60
    )


On average, Americans spend 0.32 hours sleeping per night.

4.5: Child Care


Code
childcare_totals &lt;- act |&gt;
    filter(str_starts(level2_code, "0301|0302|0303")) |&gt;
    group_by(participant_id) |&gt;
    summarize(total_childcare_min = sum(time_spent_min, na.rm = TRUE))

childcare_results &lt;- resp |&gt;
    filter(has_children == "Yes") |&gt; 
    left_join(childcare_totals, by = "participant_id") |&gt;
    mutate(total_childcare_min = replace_na(total_childcare_min, 0)) |&gt;
    summarize(
        avg_childcare_hours = weighted.mean(total_childcare_min, w = survey_weight) / 60
    )


For Americans with at least one child in the household, the average time spent on childcare activities is 0.04 hours per day


