library(gt)

##5.1 lawn care
lawn_care_summary &lt;- act |&gt;
    filter(level2_code == "020500") |&gt;
    group_by(participant_id) |&gt;
    summarize(total_lawn_min = sum(time_spent_min, na.rm = TRUE), .groups = "drop")

lawn_care_result &lt;- resp |&gt;
    # Join with the summary we just made
    left_join(lawn_care_summary, by = "participant_id") |&gt;
    # If they aren't in the lawn_care_summary, they spent 0 minutes
    mutate(total_lawn_min = replace_na(total_lawn_min, 0)) |&gt;
    # Filter for the specific groups mentioned in the project
    filter(employment_status == "Employed" | is_retired == TRUE) |&gt;
    group_by(employment_status) |&gt;
    summarize(avg_lawn_care = weighted.mean(total_lawn_min, survey_weight)) |&gt;
    # Create the GT table
    gt() |&gt;
    tab_header(title = "Lawn Care Comparison") |&gt;
    fmt_number(columns = avg_lawn_care, decimals = 2)

